165	        } else if (auto* arrayBuffer = JSC::jsDynamicCast<JSC::JSArrayBuffer*>(element)) {
166	            auto* impl = arrayBuffer->impl();
167	            if (!impl) [[unlikely]] {
168	                return Bun::ERR::INVALID_STATE(throwScope, lexicalGlobalObject, "Cannot validate on a detached buffer"_s);
169	            }
170	
171	            size_t current = impl->byteLength();
172	            any_buffer = true;
173	
174	            if (current > 0) {
175	                args.append(arrayBuffer);
176	            }
177	
178	            byteLength += current;
179	        } else {
180	            throwTypeError(lexicalGlobalObject, throwScope, "Expected TypedArray"_s);
181	            return {};
182	        }
183	    }
184	    byteLength = std::min(byteLength, maxLength);
185	
186	    if (byteLength == 0) {
187	        return returnEmptyArrayBufferView();
188	    }
189	
190	    auto buffer = JSC::ArrayBuffer::tryCreateUninitialized(byteLength, 1);
191	    if (!buffer) [[unlikely]] {
192	        throwTypeError(lexicalGlobalObject, throwScope, "Failed to allocate ArrayBuffer"_s);
193	        return {};
194	    }
195	
196	    size_t remain = byteLength;
197	    auto* head = reinterpret_cast<char*>(buffer->data());
198	
199	    if (!any_buffer) {
200	        for (size_t i = 0; i < args.size(); i++) {
201	            auto element = args.at(i);
202	            RETURN_IF_EXCEPTION(throwScope, {});
203	            auto* view = JSC::jsCast<JSC::JSArrayBufferView*>(element);
204	            size_t length = std::min(remain, view->byteLength());
205	            memcpy(head, view->vector(), length);
206	            remain -= length;
207	            head += length;
208	        }
209	    } else if (!any_typed) {
210	        for (size_t i = 0; i < args.size(); i++) {
211	            auto element = args.at(i);
212	            RETURN_IF_EXCEPTION(throwScope, {});
213	            auto* view = JSC::jsCast<JSC::JSArrayBuffer*>(element);
214	            size_t length = std::min(remain, view->impl()->byteLength());
215	            memcpy(head, view->impl()->data(), length);
216	            remain -= length;
217	            head += length;
218	        }
219	    } else {
220	        for (size_t i = 0; i < args.size(); i++) {
221	            auto element = args.at(i);
222	            RETURN_IF_EXCEPTION(throwScope, {});
223	            size_t length = 0;
224	            if (auto* view = JSC::jsDynamicCast<JSC::JSArrayBuffer*>(element)) {
225	                length = std::min(remain, view->impl()->byteLength());
226	                memcpy(head, view->impl()->data(), length);
227	            } else {
228	                auto* typedArray = JSC::jsCast<JSC::JSArrayBufferView*>(element);
229	                length = std::min(remain, typedArray->byteLength());
230	                memcpy(head, typedArray->vector(), length);
231	            }
232	
233	            remain -= length;
234	            head += length;
235	        }
236	    }
237	
238	    if (asUint8Array) {
239	        auto uint8array = JSC::JSUint8Array::create(lexicalGlobalObject, lexicalGlobalObject->m_typedArrayUint8.get(lexicalGlobalObject), WTF::move(buffer), 0, byteLength);
240	        RETURN_IF_EXCEPTION(throwScope, {});
241	        return JSValue::encode(uint8array);
242	    }
243	
244	    RELEASE_AND_RETURN(throwScope, JSValue::encode(JSC::JSArrayBuffer::create(vm, lexicalGlobalObject->arrayBufferStructure(), WTF::move(buffer))));
245	}
