444	JSC_DEFINE_HOST_FUNCTION(jsFunctionJSONLParse, (JSGlobalObject * globalObject, CallFrame* callFrame))
445	{
446	    VM& vm = globalObject->vm();
447	    auto scope = DECLARE_THROW_SCOPE(vm);
448	
449	    JSValue arg = callFrame->argument(0);
450	    if (arg.isUndefinedOrNull()) {
451	        throwTypeError(globalObject, scope, "JSONL.parse requires a string argument"_s);
452	        return {};
453	    }
454	
455	    MarkedArgumentBuffer values;
456	    JSC::StreamingJSONParseResult result;
457	
458	    if (arg.isCell() && isTypedArrayType(arg.asCell()->type())) {
459	        auto* view = jsCast<JSC::JSArrayBufferView*>(arg.asCell());
460	        if (view->isDetached()) {
461	            throwTypeError(globalObject, scope, "ArrayBuffer is detached"_s);
462	            return {};
463	        }
464	        auto* data = static_cast<const uint8_t*>(view->vector());
465	        size_t length = view->byteLength();
466	
467	        // Skip UTF-8 BOM if present
468	        if (length >= 3 && data[0] == 0xEF && data[1] == 0xBB && data[2] == 0xBF) {
469	            data += 3;
470	            length -= 3;
471	        }
472	
473	        if (length <= String::MaxLength && simdutf::validate_ascii(reinterpret_cast<const char*>(data), length)) {
474	            auto chars = std::span { reinterpret_cast<const char8_t*>(data), length };
475	            result = JSC::streamingJSONParse(globalObject, StringView(chars), values);
476	        } else {
477	            size_t u16Length = simdutf::utf16_length_from_utf8(reinterpret_cast<const char*>(data), length);
478	            if (u16Length > String::MaxLength) {
479	                throwOutOfMemoryError(globalObject, scope);
480	                return {};
481	            }
482	            auto str = WTF::String::fromUTF8ReplacingInvalidSequences(std::span { reinterpret_cast<const char8_t*>(data), length });
483	            if (str.isNull()) {
484	                throwOutOfMemoryError(globalObject, scope);
485	                return {};
486	            }
487	            result = JSC::streamingJSONParse(globalObject, str, values);
488	        }
489	    } else {
490	        auto* inputString = arg.toString(globalObject);
491	        RETURN_IF_EXCEPTION(scope, {});
492	        auto view = inputString->view(globalObject);
493	        RETURN_IF_EXCEPTION(scope, {});
494	        result = JSC::streamingJSONParse(globalObject, view, values);
495	    }
496	
497	    RETURN_IF_EXCEPTION(scope, {});
498	
499	    if (result.status == JSC::StreamingJSONParseResult::Status::Error && values.isEmpty()) {
500	        throwSyntaxError(globalObject, scope, "Failed to parse JSONL"_s);
501	        return {};
502	    }
503	
504	    RELEASE_AND_RETURN(scope, JSValue::encode(constructArray(globalObject, static_cast<ArrayAllocationProfile*>(nullptr), values)));
505	}
