507	JSC_DEFINE_HOST_FUNCTION(jsFunctionJSONLParseChunk, (JSGlobalObject * globalObject, CallFrame* callFrame))
508	{
509	    VM& vm = globalObject->vm();
510	    auto scope = DECLARE_THROW_SCOPE(vm);
511	
512	    JSValue arg = callFrame->argument(0);
513	    if (arg.isUndefinedOrNull()) {
514	        throwTypeError(globalObject, scope, "JSONL.parseChunk requires a string argument"_s);
515	        return {};
516	    }
517	
518	    MarkedArgumentBuffer values;
519	    JSC::StreamingJSONParseResult result;
520	    size_t readBytes = 0;
521	    bool isTypedArray = arg.isCell() && isTypedArrayType(arg.asCell()->type());
522	
523	    // Apply optional start/end offsets (byte offsets for typed arrays, character offsets for strings).
524	    // Populates start/end clamped to [0, length], with start <= end.
525	    size_t start;
526	    size_t end;
527	    const auto parseOffsets = [&](size_t length) {
528	        start = 0;
529	        end = length;
530	
531	        JSValue startArg = callFrame->argument(1);
532	        if (startArg.isNumber()) {
533	            double s = startArg.asNumber();
534	            if (s > 0)
535	                start = static_cast<size_t>(std::min(s, static_cast<double>(length)));
536	        }
537	
538	        JSValue endArg = callFrame->argument(2);
539	        if (endArg.isNumber()) {
540	            double e = endArg.asNumber();
541	            if (e >= 0)
542	                end = static_cast<size_t>(std::min(e, static_cast<double>(length)));
543	        }
544	
545	        if (start > end)
546	            start = end;
547	    };
548	
549	    if (isTypedArray) {
550	        auto* view = jsCast<JSC::JSArrayBufferView*>(arg.asCell());
551	        if (view->isDetached()) {
552	            throwTypeError(globalObject, scope, "ArrayBuffer is detached"_s);
553	            return {};
554	        }
555	        auto* data = static_cast<const uint8_t*>(view->vector());
556	        size_t length = view->byteLength();
557	        parseOffsets(length);
558	
559	        const uint8_t* sliceData = data + start;
560	        size_t sliceLen = end - start;
561	
562	        // Skip UTF-8 BOM if present at the start of the slice
563	        size_t bomOffset = 0;
564	        if (start == 0 && sliceLen >= 3 && sliceData[0] == 0xEF && sliceData[1] == 0xBB && sliceData[2] == 0xBF) {
565	            sliceData += 3;
566	            sliceLen -= 3;
567	            bomOffset = 3;
568	        }
569	
570	        if (sliceLen <= String::MaxLength && simdutf::validate_ascii(reinterpret_cast<const char*>(sliceData), sliceLen)) {
571	            auto chars = std::span { reinterpret_cast<const char8_t*>(sliceData), sliceLen };
572	            result = JSC::streamingJSONParse(globalObject, StringView(chars), values);
573	            // For ASCII, byte offset = character offset
574	            readBytes = start + bomOffset + result.charactersConsumed;
575	        } else {
576	            size_t u16Length = simdutf::utf16_length_from_utf8(reinterpret_cast<const char*>(sliceData), sliceLen);
577	            if (u16Length > String::MaxLength) {
578	                throwOutOfMemoryError(globalObject, scope);
579	                return {};
580	            }
581	            auto str = WTF::String::fromUTF8ReplacingInvalidSequences(std::span { reinterpret_cast<const char8_t*>(sliceData), sliceLen });
582	            if (str.isNull()) {
583	                throwOutOfMemoryError(globalObject, scope);
584	                return {};
585	            }
586	            result = JSC::streamingJSONParse(globalObject, str, values);
587	            // Convert character offset back to UTF-8 byte offset
588	            if (str.is8Bit()) {
589	                readBytes = start + bomOffset + simdutf::utf8_length_from_latin1(reinterpret_cast<const char*>(str.span8().data()), result.charactersConsumed);
590	            } else {
591	                readBytes = start + bomOffset + simdutf::utf8_length_from_utf16le(reinterpret_cast<const char16_t*>(str.span16().data()), result.charactersConsumed);
592	            }
593	        }
594	    } else {
595	        auto* inputString = arg.toString(globalObject);
596	        RETURN_IF_EXCEPTION(scope, {});
597	        auto view = inputString->view(globalObject);
598	        RETURN_IF_EXCEPTION(scope, {});
599	
600	        size_t length = view->length();
601	        parseOffsets(length);
602	
603	        if (start != 0 || end != length) {
604	            result = JSC::streamingJSONParse(globalObject, view->substring(start, end - start), values);
605	        } else {
606	            result = JSC::streamingJSONParse(globalObject, view, values);
607	        }
608	        readBytes = start + result.charactersConsumed;
609	    }
610	
611	    RETURN_IF_EXCEPTION(scope, {});
612	
613	    JSArray* array = constructArray(globalObject, static_cast<ArrayAllocationProfile*>(nullptr), values);
614	    RETURN_IF_EXCEPTION(scope, {});
615	
616	    JSValue errorValue = jsNull();
617	    if (result.status == JSC::StreamingJSONParseResult::Status::Error) {
618	        errorValue = createSyntaxError(globalObject, "Failed to parse JSONL"_s);
619	    }
620	
621	    auto* zigGlobalObject = jsCast<Zig::GlobalObject*>(globalObject);
622	    JSObject* resultObj = constructEmptyObject(vm, zigGlobalObject->jsonlParseResultStructure());
623	    resultObj->putDirectOffset(vm, 0, array);
624	    resultObj->putDirectOffset(vm, 1, jsNumber(readBytes));
625	    resultObj->putDirectOffset(vm, 2, jsBoolean(result.status == JSC::StreamingJSONParseResult::Status::Complete));
626	    resultObj->putDirectOffset(vm, 3, errorValue);
627	
628	    return JSValue::encode(resultObj);
629	}
