pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    var arena = bun.ArenaAllocator.init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();
    const input = input_slice.slice();

    const result = JSValue.createEmptyObject(globalThis, 4);
    var sections: std.StringHashMapUnmanaged(JSValue) = .{};

    var current_section = result;

    var line_iter = std.mem.splitScalar(u8, input, '\n');
    while (line_iter.next()) |raw_line| {
        const line = std.mem.trim(u8, raw_line, " \t\r");

        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        if (line[0] == '[') {
            if (line[line.len - 1] != ']') {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: malformed section header: {s}",
                    .{line},
                ));
            }
            const section_name = std.mem.trim(u8, line[1 .. line.len - 1], " \t");
            if (section_name.len == 0) {
                return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                    "INI Parse error: empty section name",
                    .{},
                ));
            }

            const gop = try sections.getOrPut(allocator, section_name);
            if (gop.found_existing) {
                current_section = gop.value_ptr.*;
            } else {
                const new_section = JSValue.createEmptyObject(globalThis, 4);
                gop.value_ptr.* = new_section;

                const section_key = bun.String.cloneUTF8(section_name);
                defer section_key.deref();
                try result.putMayBeIndex(globalThis, &section_key, new_section);

                current_section = new_section;
            }
            continue;
        }

        const eq_pos = std.mem.indexOfScalar(u8, line, '=') orelse {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: expected '=' in line: {s}",
                .{line},
            ));
        };

        const key = std.mem.trim(u8, line[0..eq_pos], " \t");
        const value = std.mem.trim(u8, line[eq_pos + 1 ..], " \t");

        if (key.len == 0) {
            return globalThis.throwValue(globalThis.createSyntaxErrorInstance(
                "INI Parse error: empty key",
                .{},
            ));
        }

        const key_str = bun.String.cloneUTF8(key);
        defer key_str.deref();
        const value_js = try bun.String.createUTF8ForJS(globalThis, value);
        try current_section.putMayBeIndex(globalThis, &key_str, value_js);
    }

    return result;
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull() or !input_value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    const obj = try input_value.toObject(globalThis);

    // First pass: top-level scalar (non-object) values as key = value
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(globalThis, obj);
        defer iter.deinit();

        while (try iter.next()) |key| {
            const val = iter.value;
            if (val.isObject() and !val.isArray()) continue;

            builder.append(.string, key);
            builder.append(.latin1, " = ");
            try appendValue(&builder, globalThis, val);
            builder.append(.lchar, '\n');
        }
    }

    // Second pass: nested plain objects become [section] headers
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(globalThis, obj);
        defer iter.deinit();

        while (try iter.next()) |key| {
            const val = iter.value;
            if (!val.isObject() or val.isArray()) continue;

            builder.append(.lchar, '[');
            builder.append(.string, key);
            builder.append(.latin1, "]\n");

            const section_obj = try val.toObject(globalThis);
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(globalThis, section_obj);
            defer section_iter.deinit();

            while (try section_iter.next()) |section_key| {
                builder.append(.string, section_key);
                builder.append(.latin1, " = ");
                try appendValue(&builder, globalThis, section_iter.value);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(globalThis);
}

fn appendValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, value: JSValue) bun.JSError!void {
    if (value.isNull() or value.isUndefined()) {
        return;
    }
    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        return;
    }
    if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
        return;
    }
    const str = try value.toBunString(globalThis);
    defer str.deref();
    builder.append(.string, str);
}

